import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): (requested, resolved)}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].rsplit('/', 1)[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                lookup[(pname, fw['framework'], pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    if k in b and k in a:
        if b[k] != a[k]:
            changes.append((proj, fw, pkg, b[k][1], a[k][1], 'Version changed'))
        else:
            unchanged.append((proj, fw, pkg, a[k][1]))
    elif k in b:
        changes.append((proj, fw, pkg, b[k][1], '-', 'Removed'))
    else:
        changes.append((proj, fw, pkg, '-', a[k][1], 'Added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:20s} {c[1]:8s} {c[2]:45s} {c[3]:10s} -> {c[4]:10s} ({c[5]})')
else:
    print('  None')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===' )
for u in unchanged:
    print(f'  {u[0]:20s} {u[1]:8s} {u[2]:45s} {u[3]}')
"

